-- =============================================================================
-- Sofia menu — fonte determinística do cardápio para custom tools (Lucinéia v9)
-- =============================================================================
-- Tabela single-row contendo cardápio em JSONB. Atualizável via SQL sem deploy.
-- Lida apenas pela edge function sofia-tools-callback (service role).

CREATE TABLE public.sofia_menu (
  id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  slug        text NOT NULL UNIQUE,
  data        jsonb NOT NULL,
  created_at  timestamptz NOT NULL DEFAULT now(),
  updated_at  timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.sofia_menu ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Admins manage sofia_menu"
  ON public.sofia_menu
  FOR ALL TO authenticated
  USING (public.has_role(auth.uid(), 'admin'))
  WITH CHECK (public.has_role(auth.uid(), 'admin'));

CREATE TRIGGER sofia_menu_updated_at
  BEFORE UPDATE ON public.sofia_menu
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

